1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_PERCENT = 10;
3	
4	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	};
11	
12	type Item = { type: string };
13	type Step = { op: "quote"; items: Item[] };
14	type Input = { customer: { yearsWithMHPCO: number }; steps: Step[] };
15	
16	const basePremium = (items: Item[]): number =>
17	  items.reduce((sum, item) => sum + BASE_PREMIUM_BY_TYPE[item.type], 0);
18	
19	const firstInsuranceSurcharge = (base: number): number =>
20	  Math.ceil((base * FIRST_INSURANCE_SURCHARGE_PERCENT) / 100);
21	
22	const quotePremium = (items: Item[]): number => {
23	  const base = basePremium(items);
24	  return base + firstInsuranceSurcharge(base) + PROCESSING_FEE;
25	};
26	
27	const executeStep = ({ items }: Step) => ({ premium: quotePremium(items) });
28	
29	export const run = (input: unknown): unknown => {
30	  const { steps } = input as Input;
31	  return { results: steps.map(executeStep) };
32	};
